/// <summary>
/// Inserting event handler for the <c>CustTable</c> table.
/// </summary>
/// <param name="_sender">Common object representing the sender.</param>
/// <param name="_e">DataEventArgs containing event data.</param>
[DataEventHandler(tableStr(CustTable), DataEventType::Inserting)]
public static void CustTable_onInserting(Common _sender, DataEventArgs _e)
{
    CustTable custTable = _sender as CustTable;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        custTable.AccountNum = custTable.ETGSPAINGenerateCustAccount();
    }
}
